49: // SkipWithGrant causes the server to start without using the privilege system at all.
50: var SkipWithGrant = false
51: 
52: var _ privilege.Manager = (*UserPrivileges)(nil)
53: var dynamicPrivs = []string{
54: 	"BACKUP_ADMIN",
55: 	"RESTORE_ADMIN",
56: 	"SYSTEM_USER",
57: 	"SYSTEM_VARIABLES_ADMIN",
58: 	"ROLE_ADMIN",
59: 	"CONNECTION_ADMIN",
60: 	"PLACEMENT_ADMIN",                 // Can Create/Drop/Alter PLACEMENT POLICY
61: 	"DASHBOARD_CLIENT",                // Can login to the TiDB-Dashboard.
62: 	"RESTRICTED_TABLES_ADMIN",         // Can see system tables when SEM is enabled
63: 	"RESTRICTED_STATUS_ADMIN",         // Can see all status vars when SEM is enabled.
64: 	"RESTRICTED_VARIABLES_ADMIN",      // Can see all variables when SEM is enabled
65: 	"RESTRICTED_USER_ADMIN",           // User can not have their access revoked by SUPER users.
66: 	"RESTRICTED_CONNECTION_ADMIN",     // Can not be killed by PROCESS/CONNECTION_ADMIN privilege
67: 	"RESTRICTED_REPLICA_WRITER_ADMIN", // Can write to the sever even when tidb_restriced_read_only is turned on.
68: 	"RESOURCE_GROUP_ADMIN",            // Create/Drop/Alter RESOURCE GROUP
69: 	"RESOURCE_GROUP_USER",             // Can change the resource group of current session.
70: }
71: var dynamicPrivLock sync.Mutex
72: var defaultTokenLife = 15 * time.Minute
