74: // UserPrivileges implements privilege.Manager interface.
75: // This is used to check privilege for the current user.
76: type UserPrivileges struct {
77: 	user string
78: 	host string
79: 	*Handle
80: 	extensionAccessCheckFuncs []extension.AccessCheckFunc
81: 	authPlugins               map[string]*extension.AuthPlugin
82: 
83: 	authPluginRequestVerification        func(user, host string, activeRoles []*auth.RoleIdentity, db, table, column string, priv mysql.PrivilegeType) bool
84: 	authPluginRequestDynamicVerification func(activeRoles []*auth.RoleIdentity, user, host, privName string, grantable bool) bool
85: }
86: 
87: // NewUserPrivileges creates a new UserPrivileges
88: func NewUserPrivileges(handle *Handle, extension *extension.Extensions) *UserPrivileges {
89: 	return &UserPrivileges{
90: 		Handle:                    handle,
91: 		extensionAccessCheckFuncs: extension.GetAccessCheckFuncs(),
92: 		authPlugins:               extension.GetAuthPlugins(),
93: 	}
94: }
