96: // RequestDynamicVerificationWithUser implements the Manager interface.
97: func (p *UserPrivileges) RequestDynamicVerificationWithUser(privName string, grantable bool, user *auth.UserIdentity) bool {
98: 	if SkipWithGrant {
99: 		return true
100: 	}
101: 
102: 	if user == nil {
103: 		return false
104: 	}
105: 
106: 	mysqlPriv := p.Handle.Get()
107: 	roles := mysqlPriv.getDefaultRoles(user.Username, user.Hostname)
108: 	return mysqlPriv.RequestDynamicVerification(roles, user.Username, user.Hostname, privName, grantable)
109: }
