111: // HasExplicitlyGrantedDynamicPrivilege checks if a user has a DYNAMIC privilege
112: // without accepting SUPER privilege as a fallback.
113: func (p *UserPrivileges) HasExplicitlyGrantedDynamicPrivilege(activeRoles []*auth.RoleIdentity, privName string, grantable bool) bool {
114: 	if SkipWithGrant {
115: 		return true
116: 	}
117: 	if p.user == "" && p.host == "" {
118: 		return true
119: 	}
120: 
121: 	mysqlPriv := p.Handle.Get()
122: 	return mysqlPriv.HasExplicitlyGrantedDynamicPrivilege(activeRoles, p.user, p.host, privName, grantable)
123: }
