125: // RequestDynamicVerification implements the Manager interface.
126: func (p *UserPrivileges) RequestDynamicVerification(activeRoles []*auth.RoleIdentity, privName string, grantable bool) bool {
127: 	if SkipWithGrant {
128: 		return true
129: 	}
130: 	if p.user == "" && p.host == "" {
131: 		return true
132: 	}
133: 
134: 	mysqlPriv := p.Handle.Get()
135: 	if !mysqlPriv.RequestDynamicVerification(activeRoles, p.user, p.host, privName, grantable) {
136: 		return false
137: 	}
138: 	return p.authPluginRequestDynamicVerification == nil || p.authPluginRequestDynamicVerification(activeRoles, p.user, p.host, privName, grantable)
139: }
