141: // RequestVerification implements the Manager interface.
142: func (p *UserPrivileges) RequestVerification(activeRoles []*auth.RoleIdentity, db, table, column string, priv mysql.PrivilegeType) bool {
143: 	if SkipWithGrant {
144: 		return true
145: 	}
146: 
147: 	if p.user == "" && p.host == "" {
148: 		return true
149: 	}
150: 
151: 	// Skip check for system databases.
152: 	// See https://dev.mysql.com/doc/refman/5.7/en/information-schema.html
153: 	dbLowerName := strings.ToLower(db)
154: 	tblLowerName := strings.ToLower(table)
155: 
156: 	// If SEM is enabled and the user does not have the RESTRICTED_TABLES_ADMIN privilege
157: 	// There are some hard rules which overwrite system tables and schemas as read-only at most.
158: 	semEnabled := sem.IsEnabled()
159: 	if semEnabled && !p.RequestDynamicVerification(activeRoles, "RESTRICTED_TABLES_ADMIN", false) {
160: 		if sem.IsInvisibleTable(dbLowerName, tblLowerName) {
161: 			return false
162: 		}
163: 		if util.IsMemOrSysDB(dbLowerName) {
164: 			switch priv {
165: 			case mysql.CreatePriv, mysql.AlterPriv, mysql.DropPriv, mysql.IndexPriv, mysql.CreateViewPriv,
166: 				mysql.InsertPriv, mysql.UpdatePriv, mysql.DeletePriv:
167: 				return false
168: 			}
169: 		}
170: 	}
171: 
172: 	if util.IsMemDB(dbLowerName) {
173: 		switch priv {
174: 		case mysql.CreatePriv, mysql.AlterPriv, mysql.DropPriv, mysql.IndexPriv, mysql.CreateViewPriv,
175: 			mysql.InsertPriv, mysql.UpdatePriv, mysql.DeletePriv, mysql.ReferencesPriv, mysql.ExecutePriv,
176: 			mysql.ShowViewPriv, mysql.LockTablesPriv:
177: 			return false
178: 		}
179: 		if dbLowerName == util.InformationSchemaName.L {
180: 			return true
181: 		} else if dbLowerName == util.MetricSchemaName.L {
182: 			// PROCESS is the same with SELECT for metrics_schema.
183: 			if priv == mysql.SelectPriv && infoschema.IsMetricTable(table) {
184: 				priv |= mysql.ProcessPriv
185: 			}
186: 		}
187: 	}
188: 
189: 	for _, fn := range p.extensionAccessCheckFuncs {
190: 		for _, dynPriv := range fn(db, table, column, priv, semEnabled) {
191: 			if !p.RequestDynamicVerification(activeRoles, dynPriv, false) {
192: 				return false
193: 			}
194: 		}
195: 	}
196: 
197: 	mysqlPriv := p.Handle.Get()
198: 	if !mysqlPriv.RequestVerification(activeRoles, p.user, p.host, db, table, column, priv) {
199: 		return false
200: 	}
201: 	return p.authPluginRequestVerification == nil || p.authPluginRequestVerification(p.user, p.host, activeRoles, db, table, column, priv)
202: }
203: 
204: // RequestVerificationWithUser implements the Manager interface.
205: func (p *UserPrivileges) RequestVerificationWithUser(db, table, column string, priv mysql.PrivilegeType, user *auth.UserIdentity) bool {
206: 	if SkipWithGrant {
207: 		return true
208: 	}
209: 	if user == nil {
210: 		return false
211: 	}
212: 	if user.Username == "" && user.Hostname == "" {
213: 		return true
214: 	}
215: 
216: 	// Skip check for INFORMATION_SCHEMA database.
217: 	// See https://dev.mysql.com/doc/refman/5.7/en/information-schema.html
218: 	if strings.EqualFold(db, "INFORMATION_SCHEMA") {
219: 		return true
220: 	}
221: 
222: 	terror.Log(p.Handle.ensureActiveUser(user.Username))
223: 	mysqlPriv := p.Handle.Get()
224: 	roles := mysqlPriv.getDefaultRoles(user.Username, user.Hostname)
225: 	return mysqlPriv.RequestVerification(roles, user.Username, user.Hostname, db, table, column, priv)
226: }
