277: func (p *UserPrivileges) isValidHash(record *UserRecord) bool {
278: 	pwd := record.AuthenticationString
279: 	if pwd == "" {
280: 		return true
281: 	}
282: 	if authPlugin, ok := p.authPlugins[record.AuthPlugin]; ok {
283: 		return authPlugin.ValidateAuthString(pwd)
284: 	}
285: 	switch record.AuthPlugin {
286: 	case mysql.AuthNativePassword:
287: 		if len(pwd) == mysql.PWDHashLen+1 {
288: 			return true
289: 		}
290: 		logutil.BgLogger().Error("the password from the mysql.user table does not match the definition of a mysql_native_password", zap.String("user", record.User), zap.String("plugin", record.AuthPlugin), zap.Int("hash_length", len(pwd)))
291: 		return false
292: 	case mysql.AuthCachingSha2Password:
293: 		if len(pwd) == mysql.SHAPWDHashLen {
294: 			return true
295: 		}
296: 		logutil.BgLogger().Error("the password from the mysql.user table does not match the definition of a caching_sha2_password", zap.String("user", record.User), zap.String("plugin", record.AuthPlugin), zap.Int("hash_length", len(pwd)))
297: 		return false
298: 	case mysql.AuthTiDBSM3Password:
299: 		if len(pwd) == mysql.SM3PWDHashLen {
300: 			return true
301: 		}
302: 		logutil.BgLogger().Error("the password from the mysql.user table does not match the definition of a tidb_sm3_password", zap.String("user", record.User), zap.String("plugin", record.AuthPlugin), zap.Int("hash_length", len(pwd)))
303: 		return false
304: 	case mysql.AuthSocket:
305: 		return true
306: 	case mysql.AuthTiDBAuthToken:
307: 		return true
308: 	case mysql.AuthLDAPSimple, mysql.AuthLDAPSASL:
309: 		return true
310: 	}
311: 
312: 	logutil.BgLogger().Error("user password from the mysql.user table not like a known hash format", zap.String("user", record.User), zap.String("plugin", record.AuthPlugin), zap.Int("hash_length", len(pwd)))
313: 	return false
314: }
