362: // GetAuthPlugin gets the authentication plugin for the account identified by the user and host
363: func (p *UserPrivileges) GetAuthPlugin(user, host string) (string, error) {
364: 	if SkipWithGrant {
365: 		return mysql.AuthNativePassword, nil
366: 	}
367: 	mysqlPriv := p.Handle.Get()
368: 	record := mysqlPriv.connectionVerification(user, host)
369: 	if record == nil {
370: 		return "", errors.New("Failed to get user record")
371: 	}
372: 	if !p.isValidHash(record) {
373: 		return "", errors.New("Failed to get plugin for user")
374: 	}
375: 	return record.AuthPlugin, nil
376: }
