378: // MatchIdentity implements the Manager interface.
379: func (p *UserPrivileges) MatchIdentity(user, host string, skipNameResolve bool) (u string, h string, success bool) {
380: 	if SkipWithGrant {
381: 		return user, host, true
382: 	}
383: 	if err := p.Handle.ensureActiveUser(user); err != nil {
384: 		logutil.BgLogger().Error("ensure user data fail",
385: 			zap.String("user", user))
386: 	}
387: 	mysqlPriv := p.Handle.Get()
388: 	record := mysqlPriv.matchIdentity(p.Handle.sctx, user, host, skipNameResolve)
389: 	if record != nil {
390: 		return record.User, record.Host, true
391: 	}
392: 	return "", "", false
393: }
