514: func (p *UserPrivileges) VerifyAccountAutoLockInMemory(user string, host string) (bool, error) {
515: 	mysqlPriv := p.Handle.Get()
516: 	record := mysqlPriv.matchUser(user, host)
517: 	if record == nil {
