728: type checkResult int
729: 
730: const (
731: 	notCheck checkResult = iota
732: 	pass
733: 	fail
734: )
735: 
736: func (p *UserPrivileges) checkSSL(priv *globalPrivRecord, tlsState *tls.ConnectionState) bool {
737: 	if priv.Broken {
738: 		logutil.BgLogger().Info("ssl check failure, due to broken global_priv record",
739: 			zap.String("user", priv.User), zap.String("host", priv.Host))
740: 		return false
741: 	}
742: 	switch priv.Priv.SSLType {
743: 	case SslTypeNotSpecified, SslTypeNone:
744: 		return true
745: 	case SslTypeAny:
746: 		r := tlsState != nil
747: 		if !r {
748: 			logutil.BgLogger().Info("ssl check failure, require ssl but not use ssl",
749: 				zap.String("user", priv.User), zap.String("host", priv.Host))
750: 		}
751: 		return r
752: 	case SslTypeX509:
753: 		if tlsState == nil {
754: 			logutil.BgLogger().Info("ssl check failure, require x509 but not use ssl",
755: 				zap.String("user", priv.User), zap.String("host", priv.Host))
756: 			return false
757: 		}
758: 		hasCert := false
759: 		for _, chain := range tlsState.VerifiedChains {
760: 			if len(chain) > 0 {
761: 				hasCert = true
762: 				break
763: 			}
764: 		}
765: 		if !hasCert {
766: 			logutil.BgLogger().Info("ssl check failure, require x509 but no verified cert",
767: 				zap.String("user", priv.User), zap.String("host", priv.Host))
768: 		}
769: 		return hasCert
770: 	case SslTypeSpecified:
771: 		if tlsState == nil {
772: 			logutil.BgLogger().Info("ssl check failure, require subject/issuer/cipher but not use ssl",
773: 				zap.String("user", priv.User), zap.String("host", priv.Host))
774: 			return false
775: 		}
776: 		if len(priv.Priv.SSLCipher) > 0 && priv.Priv.SSLCipher != util.TLSCipher2String(tlsState.CipherSuite) {
777: 			logutil.BgLogger().Info("ssl check failure for cipher", zap.String("user", priv.User), zap.String("host", priv.Host),
778: 				zap.String("require", priv.Priv.SSLCipher), zap.String("given", util.TLSCipher2String(tlsState.CipherSuite)))
779: 			return false
780: 		}
781: 		var (
782: 			hasCert      = false
783: 			matchIssuer  checkResult
784: 			matchSubject checkResult
785: 			matchSAN     checkResult
786: 		)
787: 		for _, chain := range tlsState.VerifiedChains {
788: 			if len(chain) == 0 {
789: 				continue
790: 			}
791: 			cert := chain[0]
792: 			if len(priv.Priv.X509Issuer) > 0 {
793: 				given := util.X509NameOnline(cert.Issuer)
794: 				if priv.Priv.X509Issuer == given {
795: 					matchIssuer = pass
796: 				} else if matchIssuer == notCheck {
797: 					matchIssuer = fail
798: 					logutil.BgLogger().Info("ssl check failure for issuer", zap.String("user", priv.User), zap.String("host", priv.Host),
799: 						zap.String("require", priv.Priv.X509Issuer), zap.String("given", given))
800: 				}
801: 			}
802: 			if len(priv.Priv.X509Subject) > 0 {
803: 				given := util.X509NameOnline(cert.Subject)
804: 				if priv.Priv.X509Subject == given {
805: 					matchSubject = pass
806: 				} else if matchSubject == notCheck {
807: 					matchSubject = fail
808: 					logutil.BgLogger().Info("ssl check failure for subject", zap.String("user", priv.User), zap.String("host", priv.Host),
809: 						zap.String("require", priv.Priv.X509Subject), zap.String("given", given))
810: 				}
811: 			}
812: 			if len(priv.Priv.SANs) > 0 {
813: 				matchOne := checkCertSAN(priv, cert, priv.Priv.SANs)
814: 				if matchOne {
815: 					matchSAN = pass
816: 				} else if matchSAN == notCheck {
817: 					matchSAN = fail
818: 				}
819: 			}
820: 			hasCert = true
821: 		}
822: 		checkResult := hasCert && matchIssuer != fail && matchSubject != fail && matchSAN != fail
823: 		if !checkResult && !hasCert {
824: 			logutil.BgLogger().Info("ssl check failure, require issuer/subject/SAN but no verified cert",
825: 				zap.String("user", priv.User), zap.String("host", priv.Host))
826: 		}
827: 		return checkResult
828: 	default:
829: 		panic(fmt.Sprintf("support ssl_type: %d", priv.Priv.SSLType))
830: 	}
831: }
832: 
833: func checkCertSAN(priv *globalPrivRecord, cert *x509.Certificate, sans map[util.SANType][]string) (r bool) {
834: 	r = true
835: 	for typ, requireOr := range sans {
836: 		var (
837: 			unsupported bool
838: 			given       []string
839: 		)
840: 		switch typ {
841: 		case util.URI:
842: 			for _, uri := range cert.URIs {
843: 				given = append(given, uri.String())
844: 			}
845: 		case util.DNS:
846: 			given = cert.DNSNames
847: 		case util.IP:
848: 			for _, ip := range cert.IPAddresses {
849: 				given = append(given, ip.String())
850: 			}
851: 		default:
852: 			unsupported = true
853: 		}
854: 		if unsupported {
855: 			logutil.BgLogger().Warn("skip unsupported SAN type", zap.String("type", string(typ)),
856: 				zap.String("user", priv.User), zap.String("host", priv.Host))
857: 			continue
858: 		}
859: 		var givenMatchOne bool
860: 		for _, req := range requireOr {
861: 			for _, give := range given {
862: 				if req == give {
863: 					givenMatchOne = true
864: 					break
865: 				}
866: 			}
867: 		}
868: 		if !givenMatchOne {
869: 			logutil.BgLogger().Info("ssl check failure for subject", zap.String("user", priv.User), zap.String("host", priv.Host),
870: 				zap.String("require", priv.Priv.SAN), zap.Strings("given", given), zap.String("type", string(typ)))
871: 			r = false
872: 			return
873: 		}
874: 	}
875: 	return
876: }
