986: // IsDynamicPrivilege returns true if the DYNAMIC privilege is built-in or has been registered by a plugin
987: func (p *UserPrivileges) IsDynamicPrivilege(privName string) bool {
988: 	privNameInUpper := strings.ToUpper(privName)
989: 	for _, priv := range dynamicPrivs {
990: 		if privNameInUpper == priv {
991: 			return true
992: 		}
993: 	}
994: 	return false
995: }
