997: // RegisterDynamicPrivilege is used by plugins to add new privileges to TiDB
998: func RegisterDynamicPrivilege(privName string) error {
999: 	if len(privName) == 0 {
1000: 		return errors.New("privilege name should not be empty")
1001: 	}
1002: 
1003: 	privNameInUpper := strings.ToUpper(privName)
1004: 	if len(privNameInUpper) > 32 {
1005: 		return errors.New("privilege name is longer than 32 characters")
1006: 	}
1007: 	dynamicPrivLock.Lock()
1008: 	defer dynamicPrivLock.Unlock()
1009: 	for _, priv := range dynamicPrivs {
1010: 		if privNameInUpper == priv {
1011: 			return errors.New("privilege is already registered")
1012: 		}
1013: 	}
1014: 	dynamicPrivs = append(dynamicPrivs, privNameInUpper)
1015: 	return nil
1016: }
1017: 
1018: // GetDynamicPrivileges returns the list of registered DYNAMIC privileges
1019: // for use in meta data commands (i.e. SHOW PRIVILEGES)
1020: func GetDynamicPrivileges() []string {
1021: 	dynamicPrivLock.Lock()
1022: 	defer dynamicPrivLock.Unlock()
