460: func dedupSortedKeepLast[S ~[]E, E any](s S, eq func(a, b E) bool) S {
461: 	skip := 0
462: 	for i := 1; i < len(s); i++ {
463: 		if eq(s[i], s[i-1]) {
464: 			skip++
465: 		}
466: 		s[i-skip] = s[i]
467: 	}
468: 	s = s[:len(s)-skip]
469: 	return s
470: }
