496: 	ret.columnsPriv = append(ret.columnsPriv, diff.columnsPriv...)
497: 	slices.SortStableFunc(ret.columnsPriv, compareColumnsPrivRecord)
498: 	ret.columnsPriv = dedupSortedKeepLast(ret.columnsPriv, func(x, y columnsPrivRecord) bool {
499: 		return x.Host == y.Host && x.User == y.User &&
500: 			x.DB == y.DB && x.TableName == y.TableName && x.ColumnName == y.ColumnName
501: 	})
502: 
503: 	ret.defaultRoles = make([]defaultRoleRecord, 0, len(p.defaultRoles)+len(diff.defaultRoles))
504: 	ret.defaultRoles = append(ret.defaultRoles, p.defaultRoles...)
505: 	ret.defaultRoles = append(ret.defaultRoles, diff.defaultRoles...)
506: 	slices.SortStableFunc(ret.defaultRoles, compareDefaultRoleRecord)
507: 	ret.defaultRoles = dedupSortedKeepLast(ret.defaultRoles, func(x, y defaultRoleRecord) bool {
508: 		return x.Host == y.Host && x.User == y.User
