510: 
511: 	ret.dynamicPriv = make([]dynamicPrivRecord, 0, len(p.dynamicPriv)+len(diff.dynamicPriv))
512: 	ret.dynamicPriv = append(ret.dynamicPriv, p.dynamicPriv...)
513: 	ret.dynamicPriv = append(ret.dynamicPriv, diff.dynamicPriv...)
514: 	ret.buildDynamicMap()
