517: 	ret.globalPriv = append(ret.globalPriv, p.globalPriv...)
518: 	ret.globalPriv = append(ret.globalPriv, diff.globalPriv...)
519: 	slices.SortStableFunc(ret.globalPriv, compareGlobalPrivRecord)
520: 	ret.globalPriv = dedupSortedKeepLast(ret.globalPriv, func(x, y globalPrivRecord) bool {
521: 		return x.Host == y.Host && x.User == y.User
