766: func addUserFilterCondition(sql string, userList []string) string {
767: 	if len(userList) == 0 {
768: 		return sql
769: 	}
770: 	var b strings.Builder
771: 	b.WriteString(sql)
772: 	b.WriteString(" WHERE ")
773: 	for i, user := range userList {
774: 		if i > 0 {
775: 			b.WriteString(" OR ")
776: 		}
777: 		fmt.Fprintf(&b, "USER = '%s'", sqlescape.EscapeString(user))
778: 	}
779: 	return b.String()
780: }
